form:Form.form:Scripts:
		function SelectAll()
{     
	var t,tot;
	Ctrl("leglist").DelAllRow();

  tot=Ctrl("LIST").TotalRowsCount();
	for (t=0; t<tot; t++)
		Ctrl("leglist").AddRow().SetAttr("id",Ctrl("LIST").GetAttrValue(t,"id"));

	Ctrl("LIST").Refresh();
}

function UnselectAll()
{      
 	Ctrl("leglist").DelAllRow();                
	Ctrl("LIST").Refresh();
}

function CHECK()
{ 
	switch(Ctrl("main").GetMode()) 
	{
		case "PASO2":
		case "PASO6":
			if (Ctrl("leglist").CountRow()==0)
			{
				alert("Se necesita seleccionar algun Legajo para Valorizar.");
				return false;
			}       
		break;

		case "PASO3":
			for (t=0; t<Ctrl("LIST").RowsCount(); t++)
			{                                          
				myRow=Ctrl("legasign").GetRowByAttr("id", Ctrl("LIST").GetAttrValue(t,"id"));	

				if (myRow==null) 
				{
					alert("Todos los Legajos tienen que estar asignados.");    

					Ctrl("LIST").SetXValue(Ctrl("LIST").GetAttrValue(t,"id"));
					return false;
				}
			}
		break;
	}	
	return true;
}

function NEXT()
{   
	var Id;         
	if (!CHECK()) return false;

	switch(Ctrl("main").GetMode()) 
	{
		case "PASO2":    
			var hl=new Array();
			for (t=0; t<Ctrl("leglist").CountRow(); t++)
				hl[Ctrl("leglist").GetRow(t).GetAttr("id")]=1;

			for (t=0; t<Ctrl("LIST").RowsCount(); t++)     
				if (hl[Ctrl("LIST").GetAttrValue(t,"id")])
					hl[Ctrl("LIST").GetAttrValue(t,"id")]=2;

			for (key in hl)
				if (hl[key]==1)
					Ctrl("leglist").DelRowByAttr("id",key);

			for (t=0; t<Ctrl("legasign").CountRow(); t++)
			{
				Id=Ctrl("legasign").GetRow(t).GetAttr("id");
				if (Ctrl("leglist").GetRowByAttr("id", Id)==null) 
				{                
					Ctrl("legasign").DelRow(t); t--;
					continue;
				}         
			}        

			for (t=0; t<Ctrl("legegr").CountRow(); t++)
			{
				Id=Ctrl("legegr").GetRow(t).GetAttr("oi_rem");
				if (Id!="" && Ctrl("leglist").GetRowByAttr("id", Id)==null) 
					Ctrl("legegr").GetRow(t).SetAttr("oi_rem","");
			}        
		break;

	}	
	return true;
}

function ACCEPT()
{   
	var Id;         
	if (!CHECK()) return false;

	switch(Ctrl("main").GetMode()) 
	{
		case "PASO2":
			for (t=0; t<Ctrl("LIST").RowsCount(); t++)
				if (Ctrl("leglist").GetRowByAttr("id", Ctrl("LIST").GetAttrValue(t,"id"))!=null)
					if (Ctrl("LIST").GetAttrValue(t,"grp")=="")
					{
						alert("Todos los Legajos tienen que estar asignados.");

						Ctrl("LIST").SetXValue(Ctrl("LIST").GetAttrValue(t,"id"));
						return false;
					}
		break;

	}	
	return true;
}

function Asignar()
{ 
	var t,myRow,myLeg;

	if (Ctrl("oi_grupo").GetXValue()=="") 
	{
		alert("Es necesario Seleccionar un Grupo para Realizar la Operacion.");
		return;
	}
	if (Ctrl("leglist").CountRow()==0)
	{
		alert("Es necesario Seleccionar algun Legajo para Realizar la Operacion.");
		return;
	}

	for (t=0; t<Ctrl("leglist").CountRow(); t++)
	{                                          
		myLeg=Ctrl("leglist").GetRow(t);
		myRow=Ctrl("legasign").GetRowByAttr("id", myLeg.GetAttr("id"));	

		if (myRow==null) myRow=Ctrl("legasign").AddRow();

		myRow.SetAttr("id"      ,myLeg.GetAttr("id"));
		myRow.SetAttr("oi_grupo",Ctrl("oi_grupo").GetXValue());
	}

	for (t=0; t<Ctrl("LIST").RowsCount(); t++)
	{
		if (Ctrl("leglist").GetRowByAttr("id", Ctrl("LIST").GetAttrValue(t,"id"))!=null)
		{                                                 
			Ctrl("LIST").SetAttrValueNoRefresh(t,"grp",Ctrl("oi_grupo").GetCValue());
			Ctrl("LIST").SetAttrValueNoRefresh(t,"st" , "A");
		}
	}
	Ctrl("LIST").Refresh();
}
